// --------------- Singleton cache ---------------

let _cache: { transactions: Transaction[]; profile: UserProfile } | null = null;

// --------------- Data generators ---------------

function generateMockTransactions(): Transaction[] {
  return RAW_TRANSACTIONS;
}

function generateUserProfile(): UserProfile {
  return {
    name: 'Alex Johnson',
    accountNumber: '4291',
    currentBalance: 18654.63,
    currency: DEFAULT_CURRENCY,
  };
}

// --------------- Public API ---------------

/**
 * Returns the mock financial dataset as a singleton.
 * Safe to call multiple times â€” data is computed once and cached.
 */
export function getMockData(): { transactions: Transaction[]; profile: UserProfile } {
  if (!_cache) {
    _cache = {
      transactions: generateMockTransactions(),
      profile: generateUserProfile(),
    };
  }
  return _cache;
}
